using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    // Directions: right (0,1), down (1,0)
    vector<pair<int, int>> dirs = {{0, 1}, {1, 0}};

    // Priority queue: (total_cost, i, j, time_mod)
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<tuple<long long, int, int, int>>> pq;

    // Distance matrix: dist[i][j][time_mod] where time_mod is 0 (even) or 1 (odd)
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));

    // Start at (0,0) with time_mod 1 (since first step is odd)
    long long enter_cost = (0 + 1) * (0 + 1);
    pq.push({enter_cost, 0, 0, 1});
    dist[0][0][1] = enter_cost;

    while (!pq.empty()) {
        auto [current_cost, i, j, time_mod] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (current_cost > dist[i][j][time_mod]) {
            continue;
        }

        if (time_mod == 1) {
            // Odd step: move right or down
            for (auto [di, dj] : dirs) {
                int ni = i + di;
                int nj = j + dj;
                if (ni < m && nj < n) {
                    long long new_enter_cost = (ni + 1) * (nj + 1);
                    long long new_cost = current_cost + new_enter_cost;
                    int new_time_mod = 0; // next step is even
                    if (new_cost < dist[ni][nj][new_time_mod]) {
                        dist[ni][nj][new_time_mod] = new_cost;
                        pq.push({new_cost, ni, nj, new_time_mod});
                    }
                }
            }
        } else {
            // Even step: wait
            long long wait_cost = waitCost[i][j];
            long long new_cost = current_cost + wait_cost;
            int new_time_mod = 1; // next step is odd
            if (new_cost < dist[i][j][new_time_mod]) {
                dist[i][j][new_time_mod] = new_cost;
                pq.push({new_cost, i, j, new_time_mod});
            }
        }
    }

    return -1; // should not reach here if m and n are positive
}

