                        pq.enqueue([new_cost, ni, nj, new_time_mod]);
                    }
                }
            }
        } else {
            // Even step: wait
            const new_cost = current_cost + waitCost[i][j];
            const new_time_mod = 1; // next step is odd
            if (new_cost < dist[i][j][new_time_mod]) {
                dist[i][j][new_time_mod] = new_cost;
