class MinPriorityQueue<T> {
    private heap: { element: T, priority: number }[];
    private comparator: (a: number, b: number) => number;

    constructor({ priority }: { priority: (x: T) => number }) {
        this.heap = [];
        this.comparator = (a, b) => a - b;
        this.enqueue = (element: T) => {
            const item = { element, priority: priority(element) };
            this.heap.push(item);
            this.bubbleUp();
        };
        this.dequeue = () => {
            const item = this.heap[0];
            const last = this.heap.pop();
            if (this.heap.length > 0 && last) {
                this.heap[0] = last;
                this.bubbleDown();
            }
            return item;
        };
        this.isEmpty = () => this.heap.length === 0;
    }

    private bubbleUp() {
        let index = this.heap.length - 1;
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[parentIndex].priority, this.heap[index].priority) <= 0) break;
            [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
            index = parentIndex;
        }
    }

    private bubbleDown() {
        let index = 0;
        while (true) {
            const leftChildIndex = 2 * index + 1;
            const rightChildIndex = 2 * index + 2;
            let smallerChildIndex = leftChildIndex;
            if (rightChildIndex < this.heap.length && 
                this.comparator(this.heap[rightChildIndex].priority, this.heap[leftChildIndex].priority) < 0) {
                smallerChildIndex = rightChildIndex;
            }
            if (leftChildIndex >= this.heap.length || 
                this.comparator(this.heap[index].priority, this.heap[smallerChildIndex].priority) <= 0) break;
            [this.heap[index], this.heap[smallerChildIndex]] = [this.heap[smallerChildIndex], this.heap[index]];
            index = smallerChildIndex;
        }
    }
}
