        while (nodeIdx > 0 && this._compare(nodeIdx, this._parent(nodeIdx))) {
            this._swap(nodeIdx, this._parent(nodeIdx));
            nodeIdx = this._parent(nodeIdx);
        }
    }

    private _siftDown(): void {
        let nodeIdx = 0;
        while (
            (this._leftChild(nodeIdx) < this.length && this._compare(this._leftChild(nodeIdx), nodeIdx)) ||
            (this._rightChild(nodeIdx) < this.length && this._compare(this._rightChild(nodeIdx), nodeIdx))
        ) {
            const greaterChild =
                this._rightChild(nodeIdx) < this.length &&
                this._compare(this._rightChild(nodeIdx), this._leftChild(nodeIdx))
                    ? this._rightChild(nodeIdx)
                    : this._leftChild(nodeIdx);
            this._swap(nodeIdx, greaterChild);
            nodeIdx = greaterChild;
        }
    }

    queue(value: T): void {
        this._heap.push(value);
        this.length++;
        this._siftUp();
    }

    dequeue(): T {
        if (this.length === 0) {
            throw new Error('Priority queue is empty');
        }
        const poppedValue = this._heap[0];
        const bottom = this.length - 1;
        if (bottom > 0) {
            this._swap(0, bottom);
        }
        this._heap.pop();
        this.length--;
        this._siftDown();
        return poppedValue;
    }
}
